SELECT * FROM ( SELECT f.content_id, f.title, f.overview, f.first_image FROM festival_info f WHERE EXISTS ( SELECT 1 FROM FESTIVAL_THEMES ft WHERE ft.content_id = f.content_id AND ft.theme_code IN
#{code}
) AND f.overview IS NOT NULL ORDER BY f.modified_time DESC ) WHERE ROWNUM <= 20




SELECT * FROM (
    SELECT ROWNUM AS rnum, res.* FROM (

        SELECT * FROM festival_info




                        AND (
                            title LIKE '%' || #{keyword} || '%' 
                            OR 
                            (overview IS NOT NULL AND overview LIKE '%' || #{keyword} || '%')
                        )


                        AND title LIKE '%' || #{keyword} || '%'




                AND region_code = #{region_code}


                AND sigungu_code = #{sigungu_code}


                AND event_start_date >= #{event_start_date}


                AND event_end_date <= #{event_end_date}


                AND REPLACE(event_end_date, '-', '') >= TO_CHAR(SYSDATE, 'YYYYMMDD')





                ORDER BY view_count DESC


                ORDER BY like_count DESC


                ORDER BY event_start_date ASC


                ORDER BY event_end_date ASC


                ORDER BY title ASC


                ORDER BY created_time DESC



        ) res
    WHERE ROWNUM <= #{endRow}
)
WHERE rnum >= #{startRow}


SELECT COUNT(*) FROM festival_info 




                AND (
